import { useEffect, useState } from "react"
import API from "../api/axios"

export default function Profile() {
  const [user, setUser] = useState({})

  useEffect(() => {
    API.get("/users/me").then(res => setUser(res.data))
  }, [])

  return (
    <div>
      <h2>{user.name}</h2>
      <p>{user.email}</p>
    </div>
  )
}
